import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import API from '../api/axios';
import styles from '../styles/AdminPage.module.css';

function AdminPage() {
  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [activeTab, setActiveTab] = useState('users');
  const [searchTerm, setSearchTerm] = useState('');
  const [loading, setLoading] = useState(true);
  const [showConfirmModal, setShowConfirmModal] = useState(false);
  const [selectedItem, setSelectedItem] = useState(null);
  const [modalAction, setModalAction] = useState('');

  useEffect(() => {
    fetchUsers();
    fetchPosts();
  }, []);

  const fetchUsers = async () => {
    try {
      const { data } = await API.get('/admin/users');
      setUsers(data);
    } catch (err) {
      console.error('Failed to fetch users');
    }
  };

  const fetchPosts = async () => {
    try {
      const { data } = await API.get('/admin/posts');
      setPosts(data);
    } finally {
      setLoading(false);
    }
  };

  const handleToggleStatus = async (userId) => {
    try {
      const { data } = await API.put(`/admin/users/${userId}/status`);
      setUsers(users.map(u => u._id === userId ? data.user : u));
      setShowConfirmModal(false);
    } catch (err) {
      console.error('Failed to update user status');
    }
  };

  const handleRemovePost = async (postId) => {
    try {
      await API.put(`/admin/posts/${postId}/remove`);
      setPosts(posts.map(p => p._id === postId ? { ...p, status: 'removed' } : p));
      setShowConfirmModal(false);
    } catch (err) {
      console.error('Failed to remove post');
    }
  };

  const confirmAction = (item, action) => {
    setSelectedItem(item);
    setModalAction(action);
    setShowConfirmModal(true);
  };

  const executeAction = () => {
    if (modalAction === 'toggleStatus') {
      handleToggleStatus(selectedItem._id);
    } else if (modalAction === 'removePost') {
      handleRemovePost(selectedItem._id);
    }
  };

  const activeUsers = users.filter(u => u.status === 'active').length;
  const inactiveUsers = users.filter(u => u.status === 'inactive').length;
  const publishedPosts = posts.filter(p => p.status === 'published').length;
  const removedPosts = posts.filter(p => p.status === 'removed').length;

  const filteredUsers = users.filter(user =>
    user.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    user.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const filteredPosts = posts.filter(post =>
    post.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    post.author?.name?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  if (loading) {
    return (
      <div className={styles.loadingContainer}>
        <div className={styles.loadingSpinner}></div>
      </div>
    );
  }

  return (
    <div className={styles.adminContainer}>
      {/* Sidebar */}
      <aside className={styles.sidebar}>
        <div className={styles.logo}>
          <h3>
            <span>🎮</span>
            <span>Admin</span>
          </h3>
        </div>
        <nav className={styles.sidebarNav}>
          <button 
            onClick={() => setActiveTab('dashboard')} 
            className={activeTab === 'dashboard' ? styles.activeNav : ''}
            style={{ background: 'transparent', width: '100%', textAlign: 'left' }}
          >
            <span>📊</span> <span>Dashboard</span>
          </button>
          <button 
            onClick={() => setActiveTab('users')} 
            className={activeTab === 'users' ? styles.activeNav : ''}
            style={{ background: 'transparent', width: '100%', textAlign: 'left' }}
          >
            <span>👥</span> <span>Users</span>
          </button>
          <button 
            onClick={() => setActiveTab('posts')} 
            className={activeTab === 'posts' ? styles.activeNav : ''}
            style={{ background: 'transparent', width: '100%', textAlign: 'left' }}
          >
            <span>📝</span> <span>Posts</span>
          </button>
          <button 
            onClick={() => setActiveTab('settings')} 
            className={activeTab === 'settings' ? styles.activeNav : ''}
            style={{ background: 'transparent', width: '100%', textAlign: 'left' }}
          >
            <span>⚙️</span> <span>Settings</span>
          </button>
        </nav>
      </aside>

      {/* Main Content */}
      <main className={styles.mainContent}>
        <div className={styles.header}>
          <h1>Admin Dashboard</h1>
          <p className={styles.welcomeText}>Welcome back! Here's what's happening with your community today.</p>
        </div>

        {/* Stats Grid */}
        <div className={styles.statsGrid}>
          <div className={styles.statCard}>
            <div className={styles.statIcon}>👥</div>
            <div className={styles.statValue}>{users.length}</div>
            <div className={styles.statLabel}>Total Members</div>
            <div className={styles.statTrend}>
              <span className={styles.trendUp}>↑ +12%</span> this month
            </div>
          </div>
          <div className={styles.statCard}>
            <div className={styles.statIcon}>🟢</div>
            <div className={styles.statValue}>{activeUsers}</div>
            <div className={styles.statLabel}>Active Users</div>
          </div>
          <div className={styles.statCard}>
            <div className={styles.statIcon}>🔴</div>
            <div className={styles.statValue}>{inactiveUsers}</div>
            <div className={styles.statLabel}>Inactive Users</div>
          </div>
          <div className={styles.statCard}>
            <div className={styles.statIcon}>📝</div>
            <div className={styles.statValue}>{posts.length}</div>
            <div className={styles.statLabel}>Total Posts</div>
          </div>
          <div className={styles.statCard}>
            <div className={styles.statIcon}>✅</div>
            <div className={styles.statValue}>{publishedPosts}</div>
            <div className={styles.statLabel}>Published</div>
          </div>
          <div className={styles.statCard}>
            <div className={styles.statIcon}>🗑️</div>
            <div className={styles.statValue}>{removedPosts}</div>
            <div className={styles.statLabel}>Removed</div>
          </div>
        </div>

        {/* Tabs */}
        <div className={styles.actionBar}>
          <div className={styles.sectionTitle}>
            {activeTab === 'users' ? '👥 Community Members' : activeTab === 'posts' ? '📝 All Blog Posts' : '📊 Overview'}
            <span>{activeTab === 'users' ? users.length : activeTab === 'posts' ? posts.length : ''}</span>
          </div>
          <div className={styles.searchBox}>
            <input
              type="text"
              placeholder={`Search ${activeTab === 'users' ? 'members...' : activeTab === 'posts' ? 'posts...' : '...'}`}
              className={styles.searchInput}
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        {/* Dashboard View */}
        {activeTab === 'dashboard' && (
          <div className={styles.tableContainer}>
            <div className={styles.emptyState}>
              <div className={styles.emptyIcon}>📊</div>
              <p>Welcome to your admin dashboard!</p>
              <p style={{ fontSize: '0.8rem', marginTop: '10px' }}>Select "Users" or "Posts" from the sidebar to manage content.</p>
            </div>
          </div>
        )}

        {/* Users Table */}
        {activeTab === 'users' && (
          <div className={styles.tableContainer}>
            {filteredUsers.length === 0 ? (
              <div className={styles.emptyState}>
                <div className={styles.emptyIcon}>👥</div>
                <p>No members found</p>
              </div>
            ) : (
              <table className={styles.adminTable}>
                <thead>
                  <tr>
                    <th>User</th>
                    <th>Email</th>
                    <th>Status</th>
                    <th>Joined</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredUsers.map(user => (
                    <tr key={user._id}>
                      <td>
                        <div className={styles.userInfo}>
                          <div className={styles.userAvatar}>
                            {user.name.charAt(0).toUpperCase()}
                          </div>
                          <div className={styles.userDetails}>
                            <span className={styles.userName}>{user.name}</span>
                            <span className={styles.userRole}>{user.role}</span>
                          </div>
                        </div>
                       </td>
                       <td>{user.email}</td>
                       <td>
                        <span className={`${styles.statusBadge} ${user.status === 'active' ? styles.statusActive : styles.statusInactive}`}>
                          {user.status === 'active' ? '🟢 Active' : '🔴 Inactive'}
                        </span>
                       </td>
                       <td>{new Date(user.createdAt).toLocaleDateString()}</td>
                       <td>
                        <div className={styles.actionButtons}>
                          {user.status === 'active' ? (
                            <button
                              onClick={() => confirmAction(user, 'toggleStatus')}
                              className={`${styles.btnIcon} ${styles.btnDeactivate}`}
                              title="Deactivate User"
                            >
                              🔴
                            </button>
                          ) : (
                            <button
                              onClick={() => confirmAction(user, 'toggleStatus')}
                              className={`${styles.btnIcon} ${styles.btnActivate}`}
                              title="Activate User"
                            >
                              🟢
                            </button>
                          )}
                        </div>
                       </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        )}

        {/* Posts Table */}
        {activeTab === 'posts' && (
          <div className={styles.tableContainer}>
            {filteredPosts.length === 0 ? (
              <div className={styles.emptyState}>
                <div className={styles.emptyIcon}>📝</div>
                <p>No posts found</p>
              </div>
            ) : (
              <table className={styles.adminTable}>
                <thead>
                  <tr>
                    <th>Title</th>
                    <th>Author</th>
                    <th>Status</th>
                    <th>Date</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredPosts.map(post => (
                    <tr key={post._id}>
                      <td>
                        <div className={styles.postTitle}>
                          {post.title}
                          {post.body && (
                            <div className={styles.postExcerpt}>
                              {post.body.substring(0, 60)}...
                            </div>
                          )}
                        </div>
                      </td>
                      <td>{post.author?.name || 'Unknown'}</td>
                      <td>
                        <span className={`${styles.statusBadge} ${post.status === 'published' ? styles.statusPublished : styles.statusRemoved}`}>
                          {post.status === 'published' ? '✅ Published' : '❌ Removed'}
                        </span>
                      </td>
                      <td>{new Date(post.createdAt).toLocaleDateString()}</td>
                      <td>
                        <div className={styles.actionButtons}>
                          {post.status === 'published' && (
                            <button
                              onClick={() => confirmAction(post, 'removePost')}
                              className={`${styles.btnIcon} ${styles.btnRemove}`}
                              title="Remove Post"
                            >
                              🗑️
                            </button>
                          )}
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        )}
      </main>

      {/* Confirmation Modal */}
      {showConfirmModal && (
        <div className={styles.modalOverlay} onClick={() => setShowConfirmModal(false)}>
          <div className={styles.modal} onClick={(e) => e.stopPropagation()}>
            <h3>Confirm Action</h3>
            <p>
              {modalAction === 'toggleStatus' 
                ? `Are you sure you want to ${selectedItem?.status === 'active' ? 'deactivate' : 'activate'} ${selectedItem?.name}?`
                : `Are you sure you want to remove "${selectedItem?.title}"? This action cannot be undone.`
              }
            </p>
            <div className={styles.modalButtons}>
              <button className={styles.modalCancel} onClick={() => setShowConfirmModal(false)}>
                Cancel
              </button>
              <button className={styles.modalConfirm} onClick={executeAction}>
                Confirm
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default AdminPage;
